// https://www.npmjs.com/package/finnhub (finnhub documentation

require('dotenv').config();
const finnhub = require('finnhub');
const API_KEY = process.env.API_KEY;

const finnhubClient = new finnhub.DefaultApi(API_KEY) // Replace this

//Company News
async function getCompanyNews(ticker = "APPL") {
    const today = new Date();
    const todayEST = new Intl.DateTimeFormat('en-CA', {timeZone: 'America/New_York'}).format(today); // Result: "2026-04-12"

     return new Promise((resolve , reject) => {
         finnhubClient.companyNews(ticker, todayEST, todayEST, (error, data, response) => {
             if (error) {
                 reject(error);
             } else {
                 resolve(data);
             }
         });
     });
}

async function main() {
    const data = await getCompanyNews("AAPL");
    console.log(data);
}

main();
